module bubble_sort (
    input [15:0] data_in, // 4 elements of 4 bits each
    output reg [15:0] data_out // sorted 4 elements of 4 bits each
);
    integer i, j;
    reg [3:0] swap_temp [0:3]; // temporary storage for sorting

    always @* begin
        // Load input data into temporary array
        for (i = 0; i < 4; i = i + 1) begin
            swap_temp[i] = data_in[i*4 +: 4];
        end

        // Bubble sort algorithm
        for (i = 0; i < 3; i = i + 1) begin
            for (j = 0; j < 3 - i; j = j + 1) begin
                if (swap_temp[j] > swap_temp[j + 1]) begin
                    // Swap
                    swap_temp[j] = swap_temp[j] ^ swap_temp[j + 1];
                    swap_temp[j + 1] = swap_temp[j] ^ swap_temp[j + 1];
                    swap_temp[j] = swap_temp[j] ^ swap_temp[j + 1];
                end
            end
        end

        // Load sorted data into output
        data_out = {swap_temp[3], swap_temp[2], swap_temp[1], swap_temp[0]};
    end
endmodule
